import{_ as a,o as e,c as t,a3 as n}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"75. Deductions For Board And Lodging","description":"","frontmatter":{"title":"75. Deductions For Board And Lodging","eba":"Doctors in Training 2022-2026","topics":["employment","preliminary","accommodation"]},"headers":[],"relativePath":"ebas/doctors-in-training/accommodation/75-deductions-for-board-and-lodging.md","filePath":"ebas/doctors-in-training/accommodation/75-deductions-for-board-and-lodging.md"}'),r={name:"ebas/doctors-in-training/accommodation/75-deductions-for-board-and-lodging.md"};function i(d,o,s,c,l,g){return e(),t("div",null,[...o[0]||(o[0]=[n('<h1 id="_75-deductions-for-board-and-lodging" tabindex="-1">75. Deductions For Board And Lodging <a class="header-anchor" href="#_75-deductions-for-board-and-lodging" aria-label="Permalink to &quot;75. Deductions For Board And Lodging&quot;">​</a></h1><p><strong>75.1</strong> The provisions of this clause 75 are to be read in conjunction with <a href="/eba/ebas/doctors-in-training/allowances/52-rotation-allowances.html">clause 52</a> (Rotation Allowances).</p><p><strong>75.2</strong> Where the Rotation Hospital provides board and lodging, the Doctor’s wage rate will be reduced by the amounts set out in the table in <a href="/eba/ebas/doctors-in-training/appendices/2-doctors-in-training-remuneration-allowances-and-deductions.html">Appendix 2</a>, Part 3 (Deductions for board and lodging).</p><p><strong>75.3</strong> A Health Service, with the consent of the Doctor, may charge additional amounts for services related to the board and lodging (e.g. cleaning). A Doctor may also make their own arrangements with the consent of a Health Service to ensure that services related to the board are fulfilled.</p><p><strong>75.4</strong> Health Services will not charge additional amounts for services provided that would be expected to be provided as part of the Doctor&#39;s board.</p><p><strong>75.5</strong> A Doctor may request in writing accommodation of a higher standard than provided in subclause 73.1 above, in which case the rental and other charges must be fixed by the Rotation Hospital but must not exceed prevailing market rates.</p><p>Plain language terms: board and lodging, accommodation deduction.</p>',7)])])}const p=a(r,[["render",i]]);export{m as __pageData,p as default};
